var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"같은 시간","JPN":"同時刻","ENG":"At the same time","TWN":"同一時間"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>샤레이드</color> 대균열","JPN":"管理局直轄都市<color=#ffd34c>シャレード</color>大亀裂</color>","ENG":"Administration Direct Control City, <color=#ffd34c>Charade</color> Grand Dimension Crevice","TWN":"管理局直轄城市<color=#ffd34c>查雷德</color>大峽谷"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"네놈들도 참 끈질기군.","JPN":"しつこいぞ、貴様ら。","ENG":"How persistent all of you are.","TWN":"你們還真頑強。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L7_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"설마 또다시 내 앞을 가로막을 줄이야.","JPN":"どこまでもこの私の前を立ちはだかるのだな。","ENG":"To think you would stand in my way again.","TWN":"居然又一次擋在我面前。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"천사는 가까이, 하지만 사탄은 더 가까이.","JPN":"天使と親しく、だが悪魔にはもっと親しく。","ENG":"Keep angels close. But the devil closer.","TWN":"天使近在咫尺，但撒旦更近一步。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L14_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"당신도 기억하시겠죠. 요한 추기경이 남긴 가르침입니다.","JPN":"あなたも覚えているはず。ヨハン枢機卿が残した教えです。","ENG":"You remember it, do you not? Cardinal Johan's teaching.","TWN":"你應該還記得吧，約翰樞機主教留下的教誨。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"큭큭, 기적 심의회의 모토인가? 감회가 새롭군.","JPN":"くくっ、奇跡審議会のモットーか？　感慨深いな。","ENG":"Haha. The Miracle Council's motto, was it? That brings back memories.","TWN":"呵呵，是奇蹟議會的座右銘嗎？真令人感慨。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"그 자의 가르침이라면, 이것도 기억하나?","JPN":"あの者の教えといえば、これも覚えているか？","ENG":"Then do you remember his other teaching as well?","TWN":"那你也記得他的這句話嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"의심할 수 없을 때까지 의심해라.","JPN":"疑えなくなるまで疑え。","ENG":"Doubt until thou cannot doubt any more.","TWN":"在深信不疑之前，就持續懷疑。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"허나, 네놈들이 단 한 번이라도 제대로 의심해 본 적 있나?","JPN":"だが、貴様らは一度でも、まともに疑ったことがあるのか？","ENG":"But have you ever truly doubted, even once?","TWN":"但你們真的有好好懷疑過一次嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"대체 무엇이 천사고, 무엇이 사탄이지?","JPN":"いったい何が天使で、何が悪魔だ？","ENG":"Tell me, what is an angel, and what is a devil?","TWN":"究竟什麼是天使，什麼是撒旦？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"사상과 종교가 다른 이를 배척하는 지금의 성황청이 선이라고 생각하나?","JPN":"思想と宗教が異なるという理由で人を押しのける、今の聖皇庁は善だと思うか？","ENG":"Do you truly believe the current Holy Curia, which excludes those of different beliefs and religions, is righteous?","TWN":"排斥思想與信仰不同之人的聖皇廳，真的是善嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"세상의 모든 부조리와 악덕을 방관하는 지금의 신이 선이라고 생각하나?","JPN":"世界に散らばる不条理と悪をただ傍観するだけの神が、善だと思うのか？","ENG":"Do you believe a god who turns a blind eye to all the world's injustice and vice is righteous?","TWN":"對世上一切不公與罪惡袖手旁觀的神，真的是善嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"글쎄요, 하지만 한 가지만큼은 틀림이 없겠죠.","JPN":"さあ。ですがこれだけは確かです。","ENG":"Perhaps not. But one thing is certain.","TWN":"也許吧。但至少有一點可以確定。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"광인의 논리로, 함부로 타인을 희생시키려는 당신이 옳을 리 없으니까요.","JPN":"狂人の論理で勝手に他人を犠牲にしようとするあなたが正しいはずがありません。","ENG":"Someone who sacrifices others through a maniac's logic can never be right.","TWN":"用瘋子的邏輯隨意犧牲他人的你，絕對不可能正確。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"참회의 시간은 끝났습니다!","JPN":"懺悔の時間は終わりです！","ENG":"The time for repentance is over.","TWN":"懺悔的時間結束了！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"비블리오테카! 구속하라!","JPN":"ビブリオテカ！　拘束せよ！","ENG":"Bibliotheca! Bind!","TWN":"圖書館！拘束！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"큭, 이 장소에 미리 종이를 숨겨두었나……!","JPN":"くっ、あらかじめこの場所に紙を隠しておいたか……！","ENG":"Kgh, you hid paper here in advance...?!","TWN":"嘖，事先把紙藏在這裡了嗎……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L40_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"기꺼이 정정해 드리죠, 그건 평범한 종이가 아닙니다.","JPN":"訂正させてもらいましょう。それは普通の紙ではありません。","ENG":"I would be more than happy to rephrase. That is no ordinary paper.","TWN":"容我更正，那不是普通的紙。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"오늘의 심판을 위해서, 특별히 엄선해둔 72권의 금서 페이지니까……!","JPN":"今日の審判のために厳選した、72冊の禁書ページですから！","ENG":"These are pages drawn from seventy-two handpicked forbidden books, prepared for today's judgment...!","TWN":"那是為了今日的審判，特別挑選的72本禁書書頁……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"}}}},{"id":"L42_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"금서라고? 당했군……!","JPN":"禁書だと？　くっ……！","ENG":"Forbidden books? I've been outplayed...!","TWN":"禁書？我被算計了……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"화형, 타올라라!","JPN":"火刑、燃えろ！","ENG":"Immolation. Burn!","TWN":"火刑，燃燒吧！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L47_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"으아, 으아아아아아악───!!","JPN":"く、くああああああっ——！！","ENG":"Aah– AAAAAARGH───!!","TWN":"啊、啊啊啊啊啊──！！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"이, 이정도로……!!","JPN":"こ、この程度で……！！","ENG":"N-not yet...!!","TWN":"這、這種程度就……！！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"척살, 찔러 죽여라!","JPN":"刺殺！　刺し殺せ！","ENG":"Fatal wound. Pierce and kill!","TWN":"斬首！刺殺！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L1_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"커헉……!","JPN":"がはっ……！","ENG":"Kuh...!","TWN":"咳啊……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L2_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"대답하세요. 변절자!","JPN":"答えなさい、変節者！","ENG":"Answer me. Betrayer!","TWN":"回答我，叛徒！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"어째서 예하를 살해했죠? 모든 이가 신성에 다다른 다는 건 무슨 뜻입니까!","JPN":"なぜ猊下を手にかけたのです？　すべての者が神聖に到達するというのは、どういう意味ですか！","ENG":"Why did you murder His Eminence? What do you mean by saying everyone shall reach Divinity?!","TWN":"為何殺害部下？「所有人皆能抵達神性」到底是什麼意思！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그리고 신성이라는 건……!","JPN":"そして神聖とは……！","ENG":"And this Divinity...!","TWN":"還有神性究竟是……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L5_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"안경 꼰대, 조심해! 뭔가 꾸미고 있어!","JPN":"眼鏡ばばあ、気をつけろ！　やつが何か企んでる！","ENG":"Watch out, Specky Snob! He's up to something!","TWN":"眼鏡老頭，小心！他在搞鬼！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_CHAINSAW_ATTACK_SMALL"},{"id":"L8_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"금서의 페이지를 역이용했다고? 그 짧은 시간에 구절을 외웠어?","JPN":"禁書のページを逆手にとった？　あの短時間で本の内容を読み取っただと？","ENG":"You reversed the forbidden book pages? You recited the passage in that short time?","TWN":"反向利用禁書書頁？竟然在那麼短的時間內就背下來了？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L9_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그렇다고 해도……","JPN":"だとしても……","ENG":"Even so...","TWN":"就算如此……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"음!?","JPN":"ん！？","ENG":"Mm?!","TWN":"嗯！？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"모든 이가 신성에 다다르는 것…. 그것은 곧 이런 뜻이다.","JPN":"すべての者が神聖に到達すること……それはこういうことだ。","ENG":"This is what it truly means... for all to reach Divinity.","TWN":"所有人皆能抵達神性……意思就是這樣。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"이 악취… 신부복 안쪽은 몸이 썩어 문드러졌어…….","JPN":"この悪臭……神父服の中の体が腐っている……","ENG":"This stench... your body beneath those robes is rotting away...","TWN":"這股惡臭……神父服下的身體已經腐爛了……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"베네딕트, 네놈 설마……?","JPN":"ベネディクト、あなたまさか……？","ENG":"Benedict... Don't tell me...","TWN":"本尼迪克特，你該不會……？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"보아라, 어리석은 자여. 이것이 내 신앙의 증거다.","JPN":"見ろ、愚か者よ。これが私の信仰の証だ。","ENG":"Behold, you fool. This is proof of my faith.","TWN":"看清楚，愚蠢的傢伙。這就是我信仰的證明。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"살점이 썩어서 떨어져 나가고 장기가 점점 녹아내리고 있지만, 그럼에도 움직이지.","JPN":"肉が腐り果て臓器は溶け落ちているが、それでも動いている。","ENG":"My flesh rots and falls away, my organs slowly melt, yet I still move.","TWN":"就算肉體腐朽剝落、內臟逐漸溶解，卻仍能行動自如。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"선택받지 못한 자가 신성을 품는다는 건, 이런 것이다.","JPN":"選ばれなかった者が神聖を宿すということは、つまりこういうことだ。","ENG":"This is what it means for the unchosen to bear Divinity.","TWN":"未被選中的人承載神性，就是如此下場。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"죽지도 살지도 못한 채, 그저 신념을 원동력으로 움직이는 존재.","JPN":"死ぬことも生きることもできず、ただ信念を原動力にして動く存在。","ENG":"Neither dead nor alive, driven onward by conviction alone.","TWN":"成為不生不死，只靠信念驅動的存在。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"나에게 리플레이서 시술을 해준 생물학부장은 내 꼴이 침식체와 다를 바 없다고 하더군.","JPN":"私にリプレイサー施術を施した生物学部長は、この体はもう侵食体とそう変わらない状態と言っていたな。","ENG":"The Dean of Biology who performed the Replacer enhancements told me I am no different from a C.O.","TWN":"為我施行克隆手術的生物學院院長曾說我現在的樣子，和侵蝕體沒有差別。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"리플레이서 시술이라고……?","JPN":"リプレイサー施術だと……？","ENG":"Replacer enhancements...?","TWN":"克隆手術……？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_HATE"}}}},{"id":"L31_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"그렇다. 테라사이드 프로젝트가 만들어낸 것은 신성의 모방품.","JPN":"そうだ。テラサイドプロジェクトが作り出したのは神聖の模倣品。","ENG":"Yes. What the Terraside Project created was an imitation of Divinity.","TWN":"沒錯。特拉賽德計畫製造的，是神性的仿製品。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"그 유사 신성을 인체에 적응시키기 위해, 그들은 수없이 실험을 반복했지.","JPN":"その疑似神聖を人体に適応させるため、彼らは幾度も実験を繰り返した。","ENG":"To adapt that false Divinity to the human body, they repeated experiments countless times.","TWN":"為了讓那份偽神性適應人體，他們反覆進行實驗，"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"그것이 인위적으로 그릇을 만들어내는 행위라는 것은 추호도 모른 채.","JPN":"それが人工的に器を作り出す行為だということも知らず。","ENG":"Never realizing they were artificially creating vessels.","TWN":"卻完全沒意識到，那正是人為製造器皿的行為。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"그리고 그들의 성과를 계승한 하이드리히는 어느정도 결론을 내렸어.","JPN":"そして彼らの成果を継承したハイドリヒは、それなりの結論を見出すことができた。","ENG":"And Heydrich, who carried on their work, reached a conclusion of his own.","TWN":"繼承成果的海德里希，最終得出了某種結論。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"만일 숙청당하지 않았다면 내 계획은 더 빨랐을 거다.","JPN":"彼が粛清されなかったら、私の計画にもより拍車がかかったはず。","ENG":"Had he not been purged, my plan would have progressed far faster.","TWN":"要不是被清算，我的計畫早就完成了。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"하지만 지금 나는 그 수단을 손에 넣었지……!","JPN":"だが今私はその手段を手に入れた……！","ENG":"But now, I have obtained the means...!","TWN":"但現在我已經握有那個手段……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L42_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"선택받지 못한 자가 구제될 수 있는 방법을, 모든 이가 평등해지는 세계를!","JPN":"選ばれなかった者が救済される方法を、すべての者が平等になれる世界を！","ENG":"A way for the unchosen to be saved! A world where all are equal!","TWN":"讓未被選中的人獲得救贖，讓所有人平等的世界！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"비로소 모든 인간이 <color=#ffd34c>신성에 다다르는 길</color>을 말이다……!","JPN":"すべての人間が<color=#ffd34c>神聖に到達する道</color>を……！","ENG":"At last, a path for all humankind to reach <color=#ffd34c>Divinity</color>...!","TWN":"讓全人類終於踏上<color=#ffd34c>通往神性的道路</color>……！！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"그래서? 이제 궤변은 다 끝났어, 꺽다리?","JPN":"それで？　詭弁は終わったか？　のっぽ。","ENG":"So? Are you done spouting your nonsense, Long Legs?","TWN":"所以呢？你的歪理都說完了吧，高個子？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"기가 차서 웃음도 안 나오네. 완전히 떼쟁이 등신이 되어버렸잖아?","JPN":"呆れて笑いも出ないよ。完全に駄々をこねる間抜けじゃん。","ENG":"I'm so dumbfounded I can't even laugh. You've turned into a delusional idiot!","TWN":"真是荒謬到我連笑都笑不出來。你已經變成只會耍賴的蠢貨了。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"클로디아를 데려오지 않기를 잘했어.","JPN":"クラウディアを連れてこなくて正解だった。","ENG":"Good thing we didn't bring Claudia.","TWN":"還好我沒把克勞迪婭帶來。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"지금 네 모습을 보면, 틀림없이 슬퍼했을 테니까.","JPN":"今のあんたを見たらきっと悲しんだだろうから。","ENG":"If she saw you like this, she would've been heartbroken.","TWN":"要是看到你現在這副模樣，她一定會很難過。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"근데 그건 그거고. 나, 클로디아랑 약속했거든?","JPN":"でもそれはそれ。アタシ、クラウディアと約束したんだよね。","ENG":"That aside. I made a promise to Claudia.","TWN":"不過那是另外一回事了。我和克勞迪婭約好了。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"너를 죽여 패서라도 데려오기로 말이야.","JPN":"あんたを叩きのめしてでも連れ戻すって。","ENG":"That I would drag you back, even if I had to beat you half to death.","TWN":"就算殺了你，也要把你帶回來。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L7_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"가자, 안경. 끝을 보자.","JPN":"行こう、眼鏡。決着をつけるよ。","ENG":"C'mon, Specky. Let's end this.","TWN":"走吧，眼鏡。做個了結吧。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"물론입니다, 시스터 루퍼.","JPN":"もちろんです。シスター・ルーパー。","ENG":"Of course, Sister Looper.","TWN":"當然囉，洛珀姐妹。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_PRIDE"}}}}]`);export{e as default};